import React from 'react';
import Countdown from './Countdown';

export default function Hero({ setPage }) {
  return (
    <section id="home" style={heroStyle}>
      <div style={heroBgStyle} />
      <div style={heroGridStyle} />
      <div style={contentStyle}>
        <div style={badgeStyle}>⚡ Unity Strike Force Presents</div>

        <h1 style={titleStyle}>
          <span style={{ display: 'block', color: 'var(--text)' }}>" ALLIES TO RIVALS "</span>
          <span style={{ display: 'block', color: 'var(--accent)', textShadow: '0 0 60px rgba(230,57,70,0.5)' }}>TOURNAMENT</span>
        </h1>

        <div style={seasonStyle}>SEASON 2026</div>

        <div style={metaRowStyle}>
          <MetaItem label="Start Date" value="05 JUNE 2026" />
          <div style={dividerStyle} />
          <MetaItem label="Final" value="10 JUNE 2026" />
          <div style={dividerStyle} />
          <MetaItem label="Prize Pool" value="960 CP" />
          <div style={dividerStyle} />
          <MetaItem label="Slots" value="16" />
        </div>

        <Countdown />

        <div style={{ display: 'flex', gap: 12, justifyContent: 'center', flexWrap: 'wrap', animation: 'fadeDown 0.8s ease 0.4s both' }}>
          <button onClick={() => setPage('register')} className="btn btn-primary">🎮 Register Now</button>
          <button onClick={() => setPage('info')} className="btn btn-secondary">View Details</button>
        </div>
      </div>

      {/* Register section embedded below hero */}
      <RegisterInline />
    </section>
  );
}

function RegisterInline() {
  const DISCORD_INVITE_LINK = 'https://discord.gg/8C9nA2bx';
  const STEPS = [
    { icon: '📝', step: 'Step 1', label: 'Join Discord' },
    { icon: '🎯', step: 'Step 2', label: 'Go to #registration' },
    { icon: '✅', step: 'Step 3', label: 'Submit your IGN' },
    { icon: '🎮', step: 'Step 4', label: 'Wait for Category' },
  ];

  return (
    <div id="register" style={{ width: '100%', maxWidth: 800, marginTop: 80, padding: '0 24px', boxSizing: 'border-box' }}>
      <div style={sectionHeaderStyle}>
        <p style={sectionTagStyle}>Join The Battle</p>
        <h2 style={sectionTitleStyle}>REGISTRATION</h2>
        <div style={sectionLineStyle} />
      </div>
      <div style={regCardStyle}>
        <div style={{ position: 'absolute', inset: 0, background: 'radial-gradient(ellipse at top, rgba(124,58,237,0.1), transparent 70%)', pointerEvents: 'none' }} />
        <div style={{ fontSize: '4rem', marginBottom: 16 }}>🎮</div>
        <div style={regTitleStyle}>JOIN THE TOURNAMENT</div>
        <div style={regDescStyle}>
          Register on our Discord server in the <strong>#registration</strong> channel. Submit your IGN (In-Game Name) before the deadline to secure your slot. Only 16 slots available — first come, first served!
        </div>
        <div style={deadlineStyle}>⏰ Registration Deadline: 04 June 2026 · 08:00 PM</div>
        <br />
        <a href={DISCORD_INVITE_LINK} target="_blank" rel="noreferrer" style={discordBtnStyle}
          onMouseEnter={e => { e.currentTarget.style.background = '#4752C4'; e.currentTarget.style.boxShadow = '0 12px 40px rgba(88,101,242,0.5)'; e.currentTarget.style.transform = 'translateY(-3px)'; }}
          onMouseLeave={e => { e.currentTarget.style.background = '#5865F2'; e.currentTarget.style.boxShadow = '0 8px 30px rgba(88,101,242,0.3)'; e.currentTarget.style.transform = 'none'; }}>
          <DiscordSvg />
          Join Discord Server
        </a>
        <div style={stepsGridStyle}>
          {STEPS.map(({ icon, step, label }) => (
            <div key={step} style={stepCardStyle}>
              <div style={{ fontSize: '1.5rem', marginBottom: 6 }}>{icon}</div>
